// Basics

#![allow(unused_imports)]

use std::mem;
use std::io;
use std::string;
use std::cmp::*;
use std::collections::*;

fn load() -> Vec<i64> {
    let mut line = String::new();
    io::stdin().read_line(&mut line).expect("Failed to read line");
    let vec: Vec<&str> = line.split(" ").collect();
    let mut data: Vec<i64> = Vec::new();
    for i in vec {
        let el: i64 = i.trim().parse().unwrap();
        data.push(el);
    }
    data
}

fn main() {
    let w = load();
    let (a, b) = (w[0], w[1]);
    if b - a >= 10 {
        println!("0");
    } else {
        let mut end = 1;
        for i in (a + 1)..(b + 1) {
            end *= i % 10;
        }
        println!("{}", (end % 10));
    }
}

